import {
    IMessageDataWrapper,
    IMessageParser,
} from '@nitrots/nitro-renderer/src/core';

export class GangInviteParser implements IMessageParser {
    private _inviterUsername: string = '';
    private _gangName: string = '';
    private _inviterId: number = 0;

    public flush(): boolean {
        this._inviterUsername = '';
        this._gangName = '';
        this._inviterId = 0;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        this._inviterUsername = wrapper.readString();
        this._gangName = wrapper.readString();
        this._inviterId = wrapper.readInt();
        return true;
    }

    public get inviterUsername(): string {
        return this._inviterUsername;
    }

    public get gangName(): string {
        return this._gangName;
    }

    public get inviterId(): number {
        return this._inviterId;
    }
}
